import React from 'react';
import { BrowserRouter as Router, Routes, Route, useLocation } from 'react-router-dom';
import './App.css';
import Header from './components/Header';
import Footer from './components/Footer';
import Home from './pages/Home';
import Services from './pages/Services';
import Blog from './pages/Blog';
import Contact from './pages/Contact';
import About from './pages/About';
import AgencyProfitScorePage from './pages/AgencyProfitScore';

function AppContent() {
  const location = useLocation();
  const isAgencyProfitScorePage = location.pathname === '/agency-profit-score';

  return (
    <div className="App">
      {!isAgencyProfitScorePage && <Header />}
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/services" element={<Services />} />
        <Route path="/blog" element={<Blog />} />
        <Route path="/contact" element={<Contact />} />
        <Route path="/about" element={<About />} />
        <Route path="/agency-profit-score" element={<AgencyProfitScorePage />} />
      </Routes>
      {!isAgencyProfitScorePage && <Footer />}
    </div>
  );
}

function App() {
  return (
    <Router>
      <AppContent />
    </Router>
  );
}

export default App;
